import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { AuthProvider, useAuth } from './context/AuthContext';
import { useDarkMode } from './hooks/useDarkMode';

import LoginPage        from './pages/LoginPage';
import RegisterPage     from './pages/RegisterPage';
import DashboardPage    from './pages/DashboardPage';
import ProjectsPage     from './pages/ProjectsPage';
import ProjectDetailPage from './pages/ProjectDetailPage';
import TaskDetailPage   from './pages/TaskDetailPage';
import NotificationsPage from './pages/NotificationsPage';
import AnalyticsPage    from './pages/AnalyticsPage';
import ProfilePage      from './pages/ProfilePage';
import LeaderboardPage  from './pages/LeaderboardPage';
import AppLayout        from './components/layout/AppLayout';

function DarkModeInit() {
  useDarkMode(); // Apply dark mode class on mount
  return null;
}

const ProtectedRoute = ({ children }) => {
  const { user, loading } = useAuth();
  if (loading) return <div style={{display:'flex',alignItems:'center',justifyContent:'center',height:'100vh'}}><div className="spinner spinner-lg"/></div>;
  return user ? children : <Navigate to="/login" replace/>;
};

const PublicRoute = ({ children }) => {
  const { user, loading } = useAuth();
  if (loading) return null;
  return user ? <Navigate to="/dashboard" replace/> : children;
};

const AppRoutes = () => (
  <Routes>
    <Route path="/login"    element={<PublicRoute><LoginPage/></PublicRoute>}/>
    <Route path="/register" element={<PublicRoute><RegisterPage/></PublicRoute>}/>
    <Route path="/" element={<ProtectedRoute><AppLayout/></ProtectedRoute>}>
      <Route index element={<Navigate to="/dashboard" replace/>}/>
      <Route path="dashboard"                               element={<DashboardPage/>}/>
      <Route path="projects"                                element={<ProjectsPage/>}/>
      <Route path="projects/:projectId"                     element={<ProjectDetailPage/>}/>
      <Route path="projects/:projectId/tasks/:taskId"       element={<TaskDetailPage/>}/>
      <Route path="notifications"                           element={<NotificationsPage/>}/>
      <Route path="analytics/:projectId"                    element={<AnalyticsPage/>}/>
      <Route path="leaderboard/:projectId"                  element={<LeaderboardPage/>}/>
      <Route path="profile"                                 element={<ProfilePage/>}/>
    </Route>
    <Route path="*" element={<Navigate to="/dashboard" replace/>}/>
  </Routes>
);

export default function App() {
  return (
    <AuthProvider>
      <DarkModeInit/>
      <BrowserRouter>
        <AppRoutes/>
        <Toaster position="bottom-right" toastOptions={{
          style: { background:'var(--bg-card)', color:'var(--text)', border:'1px solid var(--border)', borderRadius:10, fontSize:14 },
          success: { iconTheme: { primary:'var(--green)', secondary:'var(--green-bg)' } },
          error:   { iconTheme: { primary:'var(--red)',   secondary:'var(--red-bg)'   } },
        }}/>
      </BrowserRouter>
    </AuthProvider>
  );
}
